248→func buildSyncPromptContext(report *sessionSyncReport) string {
249→	if report == nil || !report.Attempted {
250→		return ""
251→	}
252→
253→	var b strings.Builder
254→	if report.Error != "" {
255→		fmt.Fprintf(&b, "Remote sync status: unavailable (%s). Work from local state and avoid assuming cloud execution has fully caught up.\n", report.Error)
256→		return b.String()
257→	}
258→
259→	if report.RowsUpserted == 0 {
260→		b.WriteString("Remote sync status: no new execution-state changes since the last session.\n")
261→		return b.String()
262→	}
263→
264→	fmt.Fprintf(&b, "Remote sync status: pulled %d row%s across %d table%s.\n",
265→		report.RowsUpserted,
266→		pluralSuffix(report.RowsUpserted),
267→		report.TablesUpdated,
268→		pluralSuffix(report.TablesUpdated),
269→	)
270→
271→	if report.Delta == nil {
272→		return b.String()
273→	}
274→
275→	if report.Delta.TasksSent > 0 {
276→		fmt.Fprintf(&b, "Remote sends completed: %d.\n", report.Delta.TasksSent)
277→	}
278→	if report.Delta.TasksFailed > 0 {
279→		fmt.Fprintf(&b, "Remote send failures: %d. Check `nurge tasks list` and `nurge sends list` before advancing sequences.\n", report.Delta.TasksFailed)
280→	}
281→	if report.Delta.RepliesNeedingAttention > 0 {
282→		fmt.Fprintf(&b, "Replies needing attention: %d. Check `nurge replies queue` early in the session.\n", report.Delta.RepliesNeedingAttention)
283→		for _, item := range report.Delta.RecentReplies {
284→			if strings.TrimSpace(item.Subject) != "" {
285→				fmt.Fprintf(&b, "- Reply: %s (%s) — %s\n", item.ContactEmail, item.Classification, item.Subject)
286→				continue
287→			}
288→			fmt.Fprintf(&b, "- Reply: %s (%s)\n", item.ContactEmail, item.Classification)
289→		}
290→	}
291→	if report.Delta.EnrollmentsStopped > 0 {
292→		fmt.Fprintf(&b, "Enrollments stopped remotely: %d.\n", report.Delta.EnrollmentsStopped)
293→	}
294→	if report.Delta.EnrollmentsCompleted > 0 {
295→		fmt.Fprintf(&b, "Enrollments completed remotely: %d.\n", report.Delta.EnrollmentsCompleted)
296→	}
297→	if report.Delta.SuppressionsAdded > 0 {
298→		fmt.Fprintf(&b, "Suppressions added remotely: %d.\n", report.Delta.SuppressionsAdded)
299→	}
300→	if len(report.Delta.AuthExpiredMailboxes) > 0 {
301→		fmt.Fprintf(&b, "Mailbox reconnect required: %s. Guide the user to reconnect before new sends.\n", strings.Join(report.Delta.AuthExpiredMailboxes, ", "))
302→	}
303→
304→	return b.String()
305→}
