321→func buildStrategicMemoryPromptContext(memories []session.StrategicMemory, staleSkills []session.StaleSkill) string {
322→	if len(memories) == 0 && len(staleSkills) == 0 {
323→		return ""
324→	}
325→
326→	var b strings.Builder
327→	if len(memories) > 0 {
328→		b.WriteString("Strategic memory updates:\n")
329→		for _, memory := range memories {
330→			fmt.Fprintf(&b, "- %s", memory.Summary)
331→			if len(memory.AffectedSkills) > 0 {
332→				fmt.Fprintf(&b, " Affects: %s.", strings.Join(memory.AffectedSkills, ", "))
333→			}
334→			b.WriteString("\n")
335→		}
336→	}
337→
338→	if len(staleSkills) > 0 {
339→		b.WriteString("Skills likely stale:\n")
340→		for _, item := range staleSkills {
341→			fmt.Fprintf(&b, "- %s: %s\n", item.SkillName, strings.Join(item.Reasons, "; "))
342→		}
343→		b.WriteString("If you refresh a skill, persist the new version with `nurge skills save <skill-name> --file .claude/skills/<skill-name>/SKILL.md`. Use `nurge skills stale --format json` for the full refresh list and `nurge memory list --format json` for the underlying strategic memory.\n")
344→	}
345→
346→	return b.String()
347→}
