349→func shortSyncError(err error) string {
350→	if err == nil {
351→		return ""
352→	}
353→	message := strings.TrimSpace(err.Error())
354→	if len(message) > 120 {
355→		return message[:117] + "..."
356→	}
357→	return message
358→}
