222→// inferSenderDomain tries to detect the sender's domain from connected email.
223→func inferSenderDomain(d *sql.DB) string {
224→	var fromEmail string
225→	err := d.QueryRow("SELECT from_email FROM emails LIMIT 1").Scan(&fromEmail)
226→	if err != nil {
227→		return ""
228→	}
229→	parts := strings.SplitN(fromEmail, "@", 2)
230→	if len(parts) == 2 {
231→		return strings.ToLower(parts[1])
232→	}
233→	return ""
234→}
