 13→// Save processes one enrichment input: updates the contacts table and optionally
 14→// caches the full result in enrichment_cache.
 15→func Save(db *sql.DB, input SaveInput) SaveResult {
 16→	result := SaveResult{ContactEmail: input.ContactEmail}
 17→
 18→	if input.ContactEmail == "" {
 19→		result.Error = "contact_email is required"
 20→		return result
 21→	}
 22→
 23→	// 1. Update contacts table with non-empty mapped fields.
 24→	updated, err := saveUpdateContact(db, input)
 25→	if err != nil {
 26→		result.Error = fmt.Sprintf("updating contact: %v", err)
 27→		return result
 28→	}
 29→	result.ContactUpdated = updated
 30→
 31→	// 2. Optionally cache in enrichment_cache if provider is specified.
 32→	if input.Provider != "" {
 33→		if err := saveCacheEnrichment(db, input); err != nil {
 34→			result.Error = fmt.Sprintf("caching enrichment: %v", err)
 35→			return result
 36→		}
 37→		result.CacheStored = true
 38→	}
 39→
 40→	return result
 41→}
 42→
 43→// SaveBatch processes multiple enrichment inputs and returns results for each.
 44→func SaveBatch(db *sql.DB, inputs []SaveInput) []SaveResult {
 45→	results := make([]SaveResult, 0, len(inputs))
 46→	for _, input := range inputs {
 47→		results = append(results, Save(db, input))
 48→	}
 49→	return results
 50→}
 51→
 52→// saveUpdateContact updates the contacts row for the given email with non-empty fields.
 53→func saveUpdateContact(db *sql.DB, input SaveInput) (bool, error) {
 54→	if len(input.Fields) == 0 {
 55→		return false, nil
 56→	}
 57→
 58→	var setClauses []string
 59→	var args []any
 60→
 61→	for fieldName, value := range input.Fields {
 62→		if value == "" {
 63→			continue
 64→		}
 65→		col, ok := enrichableColumns[fieldName]
 66→		if !ok {
 67→			continue
 68→		}
 69→		setClauses = append(setClauses, fmt.Sprintf("%s = ?", col))
 70→		args = append(args, value)
 71→	}
 72→
 73→	if len(setClauses) == 0 {
 74→		return false, nil
 75→	}
 76→
 77→	setClauses = append(setClauses, "updated_at = ?")
 78→	args = append(args, time.Now().UTC().Format("2006-01-02 15:04:05"))
 79→	args = append(args, input.ContactEmail)
 80→
 81→	query := fmt.Sprintf("UPDATE contacts SET %s WHERE email = ?", strings.Join(setClauses, ", "))
 82→	res, err := db.Exec(query, args...)
 83→	if err != nil {
 84→		return false, err
 85→	}
 86→	n, _ := res.RowsAffected()
 87→	return n > 0, nil
 88→}
 89→
 90→// saveCacheEnrichment upserts the enrichment result into enrichment_cache.
 91→func saveCacheEnrichment(db *sql.DB, input SaveInput) error {
 92→	dataBytes, err := json.Marshal(input.Fields)
 93→	if err != nil {
 94→		return fmt.Errorf("marshaling fields: %w", err)
 95→	}
 96→
 97→	source := input.Source
 98→	if source == "" {
 99→		source = "manual"
100→	}
101→
102→	inputKey, _ := assembly.CacheKey(input.Provider, input.ContactEmail)
103→	now := time.Now().UTC().Format("2006-01-02 15:04:05")
104→	expires := time.Now().UTC().Add(168 * time.Hour).Format("2006-01-02 15:04:05")
105→
106→	_, err = db.Exec(`
107→		INSERT INTO enrichment_cache (provider, input_key, input_data, output_data, expires_at, created_at)
108→		VALUES (?, ?, ?, ?, ?, ?)
109→		ON CONFLICT(provider, input_key) DO UPDATE SET
110→			output_data = excluded.output_data,
111→			expires_at = excluded.expires_at
112→	`, input.Provider, inputKey, input.ContactEmail, string(dataBytes), expires, now)
113→
114→	return err
115→}
